class ServiceClients:
    """Lazy-initialized shared AWS service clients (reused across warm invocations)."""

    _dynamodb = None
    _s3 = None
    _sns = None
    _sqs = None

    @classmethod
    def dynamodb(cls):
        if cls._dynamodb is None:
            cls._dynamodb = boto3.resource("dynamodb", region_name=REGION)
        return cls._dynamodb

    @classmethod
    def s3(cls):
        if cls._s3 is None:
            cls._s3 = boto3.client("s3", region_name=REGION)
        return cls._s3

    @classmethod
    def sns(cls):
        if cls._sns is None:
            cls._sns = boto3.client("sns", region_name=REGION)
        return cls._sns

    @classmethod
    def sqs(cls):
        if cls._sqs is None:
            cls._sqs = boto3.client("sqs", region_name=REGION)
        return cls._sqs


def build_response(status_code: int, body: Any, headers: Optional[dict] = None) -> dict:
    """Standardized API Gateway response builder."""
    default_headers = {
        "Content-Type": "application/json",
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "X-Request-Time": datetime.now(timezone.utc).isoformat(),
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str),
    }


def error_handler(func):
    """Decorator for consistent error handling across all microservice handlers."""

    @wraps(func)
    def wrapper(event, context):
        request_id = getattr(context, "aws_request_id", "unknown")
        function_name = getattr(context, "function_name", "unknown")

        logger.info(
            json.dumps(
                {
                    "message": "Lambda invocation started",
                    "request_id": request_id,
                    "function_name": function_name,
                    "event_source": _detect_event_source(event),
                }
            )
        )

        try:
            result = func(event, context)
            logger.info(
                json.dumps(
                    {
                        "message": "Lambda invocation completed",
                        "request_id": request_id,
                        "function_name": function_name,
                    }
                )
            )
            return result

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(
                json.dumps(
                    {
                        "message": "AWS service error",
                        "request_id": request_id,
                        "error_code": error_code,
                        "error_message": error_message,
                    }
                )
            )
            return build_response(
                502,
                {
                    "error": "Service dependency error",
                    "error_code": error_code,
                    "request_id": request_id,
                },
            )

        except ValueError as e:
            logger.warning(
                json.dumps(
                    {
                        "message": "Validation error",
                        "request_id": request_id,
                        "error": str(e),
                    }
                )
            )
            return build_response(
                400,
                {"error": "Bad request", "detail": str(e), "request_id": request_id},
            )

        except Exception as e:
            logger.exception(
                json.dumps(
                    {
                        "message": "Unhandled exception",
                        "request_id": request_id,
                        "error_type": type(e).__name__,
                        "error": str(e),
                    }
                )
            )
            return build_response(
                500,
                {"error": "Internal server error", "request_id": request_id},
            )

    return wrapper


def _detect_event_source(event: dict) -> str:
    """Detect the source of the Lambda invocation."""
    if "Records" in event:
        first_record = event["Records"][0]
        if "eventSource" in first_record:
            return first_record["eventSource"]
        if "EventSource" in first_record:
            return first_record["EventSource"]
    if "httpMethod" in event or "requestContext" in event:
        return "api-gateway"
    if "source" in event and event["source"].startswith("aws."):
        return "eventbridge"
    return "direct-invocation"


