class DynamoDBOperations:
    """Common DynamoDB operations used by multiple microservices."""

    @staticmethod
    def put_item(table_name: str, item: dict) -> dict:
        table = ServiceClients.dynamodb().Table(table_name)
        response = table.put_item(Item=item)
        logger.info(f"Put item to {table_name}: {item.get('id', 'unknown')}")
        return response

    @staticmethod
    def get_item(table_name: str, key: dict) -> Optional[dict]:
        table = ServiceClients.dynamodb().Table(table_name)
        response = table.get_item(Key=key)
        return response.get("Item")

    @staticmethod
    def update_item(table_name: str, key: dict, updates: dict) -> dict:
        table = ServiceClients.dynamodb().Table(table_name)

        update_expr_parts = []
        expr_attr_names = {}
        expr_attr_values = {}

        for i, (field, value) in enumerate(updates.items()):
            placeholder_name = f"#field{i}"
            placeholder_value = f":val{i}"
            update_expr_parts.append(f"{placeholder_name} = {placeholder_value}")
            expr_attr_names[placeholder_name] = field
            expr_attr_values[placeholder_value] = value

        update_expression = "SET " + ", ".join(update_expr_parts)

        response = table.update_item(
            Key=key,
            UpdateExpression=update_expression,
            ExpressionAttributeNames=expr_attr_names,
            ExpressionAttributeValues=expr_attr_values,
            ReturnValues="ALL_NEW",
        )
        return response.get("Attributes", {})

    @staticmethod
    def query_items(table_name: str, key_condition_expression, expression_values: dict,
                    index_name: Optional[str] = None, limit: int = 100) -> list:
        table = ServiceClients.dynamodb().Table(table_name)
        kwargs = {
            "KeyConditionExpression": key_condition_expression,
            "ExpressionAttributeValues": expression_values,
            "Limit": limit,
        }
        if index_name:
            kwargs["IndexName"] = index_name

        response = table.query(**kwargs)
        return response.get("Items", [])

    @staticmethod
    def delete_item(table_name: str, key: dict) -> dict:
        table = ServiceClients.dynamodb().Table(table_name)
        return table.delete_item(Key=key)


