class S3Operations:
    """Common S3 operations used by multiple microservices."""

    @staticmethod
    def upload_json(bucket: str, key: str, data: Any) -> dict:
        response = ServiceClients.s3().put_object(
            Bucket=bucket,
            Key=key,
            Body=json.dumps(data, default=str),
            ContentType="application/json",
        )
        logger.info(f"Uploaded JSON to s3://{bucket}/{key}")
        return response

    @staticmethod
    def download_json(bucket: str, key: str) -> Any:
        response = ServiceClients.s3().get_object(Bucket=bucket, Key=key)
        content = response["Body"].read().decode("utf-8")
        return json.loads(content)

    @staticmethod
    def delete_object(bucket: str, key: str) -> dict:
        return ServiceClients.s3().delete_object(Bucket=bucket, Key=key)

    @staticmethod
    def list_objects(bucket: str, prefix: str, max_keys: int = 1000) -> list:
        response = ServiceClients.s3().list_objects_v2(
            Bucket=bucket, Prefix=prefix, MaxKeys=max_keys
        )
        return response.get("Contents", [])

    @staticmethod
    def generate_presigned_url(bucket: str, key: str, expiration: int = 3600) -> str:
        return ServiceClients.s3().generate_presigned_url(
            "get_object",
            Params={"Bucket": bucket, "Key": key},
            ExpiresIn=expiration,
        )


